connection_mgr__bluetooth__pairing__connection__text = TextObject(bs_BA="Veza se uspostavlja. Sačekajte...", cs_CZ="Spojení se navazuje. Čekejte prosím...", da_DK="Der oprettes forbindelse. Vent...", de_DE="Die Verbindung wird hergestellt.\nBitte warten...", el_GR="Δημιουργείται η σύνδεση.\nΠαρακαλώ περιμένετε...", en_GB="Establishing connection. Please wait...", es_ES="Estableciendo la conexión.\nPor favor, espere...", fi_FI="Yhteys muodostuu. Odota...", fr_FR="Établissement de la connexion en cours.\nVeuillez patienter...", hr_HR="Veza se uspostavlja. Čekajte...", hu_HU="Kapcsolat létrehozása. Kérem, várjon...", it_IT="Collegamento in corso. Attendere prego...", nl_NL="De verbinding wordt opgebouwd.\nWachten a.u.b...", no_NO="Oppretter forbindelse. Vent litt...", pl_PL="Nawiązywanie połączenia. Proszę czekać...", pt_PT="A estabelecer a ligação. Por favor, aguarde...", ro_RO="Se realizează conexiunea. Aşteptaţi...", ru_RU="Установление соединения.\nПожалуйста, ждите...", sk_SK="Spojenie sa vytvára. Čakajte, prosím...", sl_SI="Povezava se vzpostavlja.\nProsimo, počakajte ...", sr_RS="Veza se uspostavlja. Molimo sačekajte...", sv_SE="Anslutningen upprättas. Var god vänta...", tr_TR="Bağlantı kuruluyor. Lütfen bekleyin...", uk_UA="Встановлюється з’єднання. Зачекайте...")
connection_mgr__bluetooth__pairing__no_device_found__text = TextObject(bs_BA="Nisu pronađeni uređaji.", cs_CZ="Nebyla nalezena žádná zařízení.", da_DK="Ingen apparater fundet", de_DE="Es wurden keine Geräte gefunden.", el_GR="Δεν βρέθηκαν συσκευές.", en_GB="No devices were found.", es_ES="No se han encontrado dispositivos.", fi_FI="Laitteita ei löytynyt.", fr_FR="Aucun périphérique n'a été trouvé.", hr_HR="Nisu pronađeni nikakvi uređaji.", hu_HU="Nem találhatók készülékek.", it_IT="Non è stato trovato nessun dispositivo.", nl_NL="Er zijn geen apparaten gevonden.", no_NO="Finner ingen enheter.", pl_PL="Nie znaleziono urządzeń.", pt_PT="Não foram encontrados aparelhos.", ro_RO="Nu s-au găsit dispozitive.", ru_RU="Устройства не найдены.", sk_SK="Nenašli sa žiadne prístroje.", sl_SI="Ni najdenih naprav.", sr_RS="Nije pronađen nijedan uređaj.", sv_SE="Inga enheter hittades.", tr_TR="Hiçbir cihaz bulunamadı.", uk_UA="Не знайдено жодного пристрою.")
connection_mgr__bluetooth__pairing__search_with_vehicle_name__text = TextObject(bs_BA="Naziv vozila:\n%1\n\nUvjerite se da je Bluetooth uključen na\nVašem uređaju i da je aktivirana vidljivost.", cs_CZ="Jméno vozidla:\n%1\n\nZkontrolujte prosím, že je Bluetooth ve\nVašem zařízení zapnutý a byla aktivována\nviditelnost.", da_DK="Bilens navn:\n%1\n\nKontroller, at Bluetooth er aktiveret på dit\napparat, og at synligheden er aktiveret.", de_DE="Fahrzeugname:\n%1\n\nBitte stelle sicher, dass Bluetooth an deinem\nGerät eingeschaltet ist und die Sichtbarkeit\naktiviert wurde.", el_GR="Όνομα οχήματος:\n%1\n\nΣιγουρευτείτε ότι είναι ενεργοποιημένο το\nBluetooth στη συσκευή σας και ότι\nενεργοποιήθηκε η ορατότητα.", en_GB="Vehicle name:\n%1\n\nPlease check that Bluetooth is activated on\nyour device and discoverability is switched\non.", es_ES="Nombre del vehículo:\n%1\n\nPor favor, asegúrese de que el Bluetooth está\nactivado en su dispositivo y de haber\nactivado la visibilidad.", fi_FI="Auton nimi:\n%1\n\nVarmista, että laitteesi Bluetooth on kytketty\npäälle ja näkyvyys on aktivoitu.", fr_FR="Nom du véhicule:\n%1\n\nVeuillez vous assurer que la fonction\nBluetooth est activée sur votre périphérique\net que ce dernier est visible.", hr_HR="Naziv vozila:\n%1\n\nProvjerite je li uključen Bluetooth na vašem\nuređaju i je li aktivirana vidljivost.", hu_HU="Jármű neve:\n%1\n\nKérünk, ellenőrizd, hogy a Bluetooth be\nvan-e kapcsolva a készülékeden, és a\nláthatóság aktiválásra került-e.", it_IT="Nome vettura:\n%1\n\nAccertarsi che la funzione Bluetooth del\ndispositivo sia accesa e che sia attivata la\nvisibilità.", nl_NL="Naam voertuig:\n%1\n\nZorg ervoor dat Bluetooth is ingeschakeld op\nje apparaat en de zichtbaarheid is\ngeactiveerd.", no_NO="Bilens navn:\n%1\n\nForsikre deg om at Bluetooth er slått på\npå enheten, og at den er synlig.", pl_PL="Nazwa pojazdu:\n%1\n\nProszę się upewnić, że funkcja Bluetooth w\nTwoim urządzeniu jest włączona i została\naktywowana jego widoczność.", pt_PT="Nome do veículo:\n%1\n\nPor favor, certifica-te que o Bluetooth está\nligado no teu aparelho e que a visibilidade foi\nativada.", ro_RO="Nume autovehicul:\n%1\n\nAsiguraţi-vă că Bluetooth este activat pe\ndispozitivul dumneavoastră şi că a fost\nactivată vizibilitatea.", ru_RU="Имя автомобиля:\n%1\n\nПожалуйста, убедитесь, что функция\nBluetooth в Вашем устройстве включена, а\nтакже активирована функция видимости.", sk_SK="Názov vozidla:\n%1\n\nProsím, uistite sa, že Bluetooth na vašom\nzariadeníi je zapnutý a viditeľnosť bola\naktivovaná.", sl_SI="Ime vozila:\n%1\n\nPreverite, da je Bluetooth na vaši napravi\nvključen in vidnost aktivirana.", sr_RS="Naziv vozila:\n%1\n\nUverite se da je Bluetooth na vašem uređaju\nuključen i vidljivost aktivirana.", sv_SE="Fordonsnamn:\n%1\n\nSe till att Bluetooth har aktiverats på din\nenhet och att synlighet har aktiverats.", tr_TR="Araç adı:\n%1\n\nLütfen cihazında Bluetooth özelliğinin açık ve\ngörünürlüğün aktif olduğundan emin ol.", uk_UA="Ім’я автомобіля:\n%1\n\nПереконайтеся, що на пристрої ввімкнено\nBluetooth і пристрій зроблено видимим.")
connection_mgr__bluetooth__pairing__simple_compare__top_text = TextObject(bs_BA="Potvrdite PIN za Bluetooth vezu na\nmobilnom telefonu:\n%1\nObratite pažnju na dodatne napomene na\nmobilnom telefonu.", cs_CZ="Potvrďte prosím PIN pro připojení Bluetooth\nna mobilním telefonu:\n%1\nDodržujte další pokyny na mobilním\ntelefonu.", da_DK="Bekræft pinkoden til Bluetooth-forbindelsen\npå mobiltelefonen:\n%1\nVær opmærksom på yderligere anvisninger\npå mobiltelefonen.", de_DE="Bitte bestätige die PIN für die\nBluetooth-Verbindung auf dem Mobiltelefon:\n%1\nBitte beachte weitere Hinweise auf dem\nMobiltelefon.", el_GR="Επιβεβαιώστε το PIN για τη σύνδεση\nBluetooth στο κινητό τηλέφωνο:\n%1\nΠροσέξτε τυχόν περαιτέρω υποδείξεις στο\nκινητό τηλέφωνο.", en_GB="Please confirm the PIN for the Bluetooth\nconnection on the mobile phone:\n%1\nPlease follow the instructions on the mobile\nphone.", es_ES="Por favor, confirme el PIN para la conexión\nBluetooth en el teléfono móvil:\n%1\nSiga las indicaciones que aparezcan en el\nteléfono móvil.", fi_FI="Vahvista PIN-koodi Bluetooth-yhteyttä\nvarten matkapuhelimesta:\n%1\nHuomioi muut ohjeet\nmatkapuhelimen näytöllä.", fr_FR="Veuillez confirmer sur le téléphone portable\nle code PIN pour la connexion Bluetooth:\n%1\nVeuillez tenir compte des indications\nsur le téléphone portable.", hr_HR="Potvrdite PIN za Bluetooth vezu na\nmobilnom telefonu:\n%1\nUvažite daljnje napomene na mobilnom\ntelefonu.", hu_HU="Kérünk, erősítsd meg a Bluetooth-kapcsolat\nPIN-kódját a mobiltelefonon:\n%1\nKérünk, vedd figyelembe a további\ninformációkat a mobiltelefonon.", it_IT="Confermare il PIN per il collegamento\nBluetooth sul telefono cellulare:\n%1\nOsservare le ulteriori istruzioni sul telefono\ncellulare.", nl_NL="Bevestig je pincode voor de\nBluetoothverbinding op je mobiele telefoon:\n%1\nVolg de verdere aanwijzingen op je mobiele\ntelefoon.", no_NO="Bekreft PIN-koden for\nBluetooth-forbindelsen\npå mobiltelefonen:\n%1\nFølg annen informasjon på mobiltelefonen.", pl_PL="Proszę potwierdzić kod PIN połączenia\nBluetooth w telefonie komórkowym:\n%1\nProszę stosować się do dalszych wskazówek\nwyświetlanych w telefonie komórkowym.", pt_PT="Por favor, confirma o PIN para a ligação\nBluetooth no teu telemóvel:\n%1\nPor favor, segue as restantes instruções no\nteu telemóvel.", ro_RO="Confirmaţi codul PIN pentru conexiunea\nBluetooth pe telefonul mobil:\n%1\nRespectaţi indicaţiile suplimentare de pe\ntelefonul mobil.", ru_RU="Пожалуйста, подтвердите PIN для\nсоединения Bluetooth на мобильном\nтелефоне:\n%1\nОбратите внимание на дополнительные\nуказания на мобильном телефоне.", sk_SK="Prosím, potvrďte kód PIN pre pripojenie\nBluetooth na mobilnom telefóne:\n%1\nProsím, dbajte na ďalšie pokyny v mobilnom\ntelefóne.", sl_SI="Potrdite PIN-kodo za Bluetooth povezavo na\nmobilnem telefonu:\n%1\nUpoštevajte nadaljnje napotke na mobilnem\ntelefonu.", sr_RS="Potvrdite PIN za povezivanje sa Bluetooth na\nmobilnom telefonu:\n%1\nObratite pažnju na dodatne napomene na\nmobilnom telefonu.", sv_SE="Bekräfta PIN-koden för Bluetoothanslutning\npå mobiltelefonen:\n%1\nObservera ytterligare anvisningar på\nmobiltelefonen.", tr_TR="Lütfen cep telefonunda Bluetooth bağlantısı\niçin PIN'i onayla:\n%1\nLütfen cep telefonundaki diğer notları\ndikkate al.", uk_UA="Будь ласка, підтвердьте PIN-код для\nз'єднання Bluetooth на мобільному\nтелефоні:\n%1\nЗверніть увагу на додаткові вказівки на\nмобільному телефоні.")
connection_mgr__bluetooth__pairing__successful_connected__text = TextObject(bs_BA="Proces povezivanja je uspješno završen.\nMože potrajati nekoliko trenutaka do\nuspostavljanja veze.\n\nObratite pažnju na moguće napomene\nna uređaju.", cs_CZ="Proces párování byl úspěšně dokončen.\nNavázání spojení může trvat několik\nokamžiků.\n\nBerte prosím na vědomí veškeré pokyny na\nzařízení.", da_DK="Parring blev afsluttet korrekt. Det kan tage\net øjeblik, inden der oprettes forbindelse.\n\nVær opmærksom på mulige anvisninger\npå apparatet.", de_DE="Der Kopplungsprozess wurde erfolgreich\nabgeschlossen. Es kann einige Augenblicke\ndauern, bis die Verbindung hergestellt wird.\n\nBitte beachte mögliche Hinweise auf dem\nGerät.", el_GR="Η διαδικασία σύζευξης ολοκληρώθηκε με\nεπιτυχία. Μπορεί να χρειαστούν μερικές\nστιγμές, ώσπου να δημιουργηθεί η σύνδεση.\n\nΛάβετε υπόψη σας ενδεχόμενες υποδείξεις\nστη συσκευή.", en_GB="The device was paired successfully.\nIt may take a few moments for the\nconnection to be established.\n\nPlease follow any instructions on the device.", es_ES="La vinculación ha finalizado correctamente.\nLa conexión puede tardar unos instantes.\n\nSiga las indicaciones que aparezcan en el\ndispositivo.", fi_FI="Kytkentäprosessi onnistui. Yhteyden\nmuodostaminen saattaa kestää hetken.\n\nHuomioi mahdolliset ohjeet laitteen\nnäytöllä.", fr_FR="La procédure de jumelage a été réalisée avec\nsuccès. L'établissement de la connexion peut\nprendre quelques instants.\n\nVeuillez tenir compte des possibles\nindications sur le périphérique.", hr_HR="Proces povezivanja uspješno je završen.\nMože potrajati nekoliko trenutaka dok se ne\nuspostavi veza.\n\nUvažite eventualne napomene na uređaju.", hu_HU="A párosítási folyamat sikeresen befejeződött.\nA kapcsolat létrehozásához néhány pillanat\nszükséges.\n\nVedd figyelembe a készüléken megjelenő\nesetleges figyelmeztetéseket.", it_IT="Il processo di abbinamento è stato\ncompletato correttamente. La creazione del\ncollegamento potrebbe richiedere qualche\nistante.\nOsservare le eventuali istruzioni sul\ndispositivo.", nl_NL="Het koppelingsproces is afgesloten. Het kan\neventjes duren voordat de verbinding tot\nstand is gebracht.\n\nHoud rekening met de aanwijzingen\nop je apparaat.", no_NO="Tilkoblingen er fullført. Det kan ta en liten\nstund før forbindelsen er opprettet.\n\n\nSe eventuelle meldinger på enheten.", pl_PL="Proces parowania został pomyślnie\nzakończony. Nawiązanie połączenia może\npotrwać kilka chwil.\n\nZwracaj uwagę na możliwe komunikaty\nw urządzeniu.", pt_PT="O emparelhamento foi concluído com\nsucesso. Pode demorar um pouco até a\nligação serestabelecida.\n\nPor favor, verifica possíveis indicações\nno aparelho.", ro_RO="Procesul de asociere s-a încheiat cu succes.\nPoate dura câteva momente, până la\nrealizarea conexiunii.\n\nŢineţi cont de posibilele indicaţii de pe\naparat.", ru_RU="Процесс сопряжения успешно завершен.\nУстановление соединения может занять\nнесколько минут.\n\nСледуйте инструкциям на устройстве.", sk_SK="Proces spojenia bol úspešne ukončený. Môže\nchvíľu trvať, kým sa vytvorí spojenie.\n\nProsím, dbajte na všetky upozornenia\nna zariadení.", sl_SI="Postopek seznanjanja je bil uspešno\nzaključen. Lahko traja nekaj trenutkov, da se\npovezava vzpostavi.\n\nUpoštevajte morebitne napotke na\nvaši napravi.", sr_RS="Proces povezivanja je uspešno završen.\nMože da potraje nekoliko trenutaka do\nuspostavljanja veze.\n\nObratite pažnju na moguće napomene\nna uređaju.", sv_SE="Kopplingsprocessen lyckades. Det kan ta en\nstund innan anslutningen är upprättad.\n\nObservera eventuell information på enheten.", tr_TR="Eşleştirme işlemi başarıyla tamamlandı.\nBağlantı kurulana kadar birkaç dakika\nsürebilir.\n\nLütfen cihazdaki olası notları dikkate al.", uk_UA="Процес створення пари успішно\nзавершено. Встановлення з'єднання може\nзайняти кілька хвилин.\n\nДотримуйтесь інструкцій на пристрої.")
