connection_mgr__error_or_hint_texts___ecall_number_not_valid_missing_country_code_text = TextObject(bs_BA="Dodajte „00” za pozivni broj zemlje, npr. 00387 za Bosnu i Hercegovinu.", cs_CZ="Přidejte prosím „00“ pro předvolbu země, např. 0049 pro Německo.", da_DK="Tilføj \"00\" til landekoden, fx 0045 for Danmark.", de_DE="Bitte ergänze \"00\" für die Ländervorwahl, z. B. 0049 für Deutschland.", el_GR="Συμπληρώστε \"00\" για τον κωδικό κλήσης χώρας, π.χ., 0049 για την Γερμανία.", en_GB="Please add \"00\" for the country code, e.g. 0044 for Great Britain.", es_ES="Añada \"00\" delante del prefijo del país: p. ej., 0034 para España.", fi_FI="Lisää maatunnuksen eteen \"00\", esim. Suomessa 00358.", fr_FR="Veuillez ajouter «00» pour l'indicatif du pays, par ex. 0033 pour la France.", hr_HR="Dopunite \"00\" za pozivni broj zemlje, npr. 0049 za Njemačku.", hu_HU="Egészítsd ki az országhívószámot „00”-val, pl. 0049 Németország esetében.", it_IT="Aggiungere \"00\" per il prefisso internazionale, ad es. 0039 per l'Italia.", nl_NL="Voeg \"00\" toe voor de landcode, bijv. 0031 voor Nederland.", no_NO="Bruk 00 foran landskoden, f.eks. 0047 for Norge.", pl_PL="Dopisz „00” do numeru kierunkowego kraju, np. 0048 w przypadku Polski.", pt_PT="Por favor, adicione \"00\" ao indicativo do país, por ex., 00351 para Portugal.", ro_RO="Completaţi \"00\" pentru prefixul de ţară, de ex. 0049 pentru Germania.", ru_RU="Добавьте «00» для кода страны, например, 007 для России.", sk_SK="Prosím, doplňte „00“, pre predvoľbu krajiny, napr. 00421 pre Slovensko.", sl_SI="Dopolnite \"00\" za klicno številko države, npr. 00386 za Slovenijo.", sr_RS="Dodajte „00” za pozivni broj zemlje, npr. 00381 za Srbiju.", sv_SE="Vänligen lägg till \"00\" för landskoden, t.ex. 0046 för Sverige.", tr_TR="Lütfen ülke kodu için “00” ekle, örneğin Türkiye için 0090.", uk_UA="Додайте «00» до коду країни, наприклад, 00380 для України.")
connection_mgr__error_or_hint_texts___hotspot__setting__change_password__user_name_field__insufficient_input = TextObject(bs_BA="Unesite najmanje 12 znakova (velika slova, mala slova, brojevi, opcionalno: posebni znakovi).", cs_CZ="Zadejte prosím alespoň 12 znaků (velká a malá písmena, číslice; nepovinně: speciální znaky).", da_DK="Angiv mindst 12 tegn (store bogstaver, små bogstaver, tal; frivilligt: Specialtegn).", de_DE="Bitte gib mindestens 12 Zeichen ein (Groß-, Kleinbuchstaben, Zahlen; optional: Sonderzeichen).", el_GR="Καταχωρίστε τουλάχιστον 12 χαρακτήρες (κεφαλαία γράμματα, πεζά γράμματα, αριθμούς. Προαιρετικά: ειδικούς χαρακτήρες).", en_GB="Please enter at least 12 characters (upper case letter, lower case letter, number, optional: special character).", es_ES="Por favor, introduzca por lo menos 12 caracteres (mayúsculas, minúsculas y números; opcionalmente, caracteres especiales).", fi_FI="Syötä vähintään 12 merkkiä (isoja ja pieniä kirjaimia, numeroita sekä valinnaisesti erikoismerkkejä).", fr_FR="Veuillez entrer au moins 12 caractères (des majuscules, des minuscules, des chiffres, en option: des caractères spéciaux).", hr_HR="Unesite najmanje 12 znakova (velika i mala slova, brojke; opcijski: posebne znakove).", hu_HU="Írj be legalább 12 karaktert (nagybetűket, kisbetűket, számokat; opcionálisan: speciális karaktereket).", it_IT="Immettere almeno 12 caratteri (lettere maiuscole, lettere minuscole, numeri; facoltativo: caratteri speciali).", nl_NL="Voer ten minste 12 tekens in (hoofdletters, kleine letters, cijfers; optioneel: speciale tekens).", no_NO="Legg inn minst 12 tegn (bruk store og små bokstaver, tall og eventuelt spesialtegn).", pl_PL="Wpisz co najmniej 12 znaków (wielkie i małe litery, cyfry, opcjonalnie: znaki specjalne).", pt_PT="Por favor, insere pelo menos 12 carateres (letras maiúsculas e minúsculas, números; opcional: carateres especiais).", ro_RO="Introduceţi cel puţin 12 caractere (litere mari, litere mici, cifre; opţional: caractere speciale).", ru_RU="Пожалуйста, введите не менее 12 символов (верхний регистр, нижний регистр, цифры; опционально: специальные символы).", sk_SK="Prosím, zadajte najmenej 12 znakov (veľké, malé písmená, čísla; voliteľné špeciálne znaky).", sl_SI="Vnesite vsaj 12 znakov (velike črke, male črke, številke; neobvezno: posebni znaki).", sr_RS="Unesite najmanje 12 znakova (velika slova, mala slova, brojevi; opciono: posebni znaci).", sv_SE="Ange minst 12 tecken (stora och små bokstäver, siffror; valfritt: specialtecken).", tr_TR="Lütfen en az 12 karakter (büyük ve küçük harfler, sayılar; isteğe bağlı: özel karakterler) gir.", uk_UA="Введіть щонайменше 12 символів (великі та малі літери, цифри; опціонально: спеціальні символи).")
