phone_not_attached__bluetooth_turning_on_text = TextObject(bs_BA="Bluetooth se aktivira.", cs_CZ="Aktivuje se Bluetooth.", da_DK="Bluetooth aktiveres.", de_DE="Bluetooth wird aktiviert.", el_GR="Θα γίνει ενεργοποίηση του Bluetooth.", en_GB="Bluetooth will be activated.", es_ES="Activando Bluetooth.", fi_FI="Bluetooth aktivoidaan.", fr_FR="Activation du Bluetooth en cours.", hr_HR="Bluetooth se aktivira.", hu_HU="Bluetooth aktiválása.", it_IT="Attivazione del Bluetooth in corso.", nl_NL="Bluetooth wordt geactiveerd.", no_NO="Aktiverer Bluetooth.", pl_PL="Zostaje włączona funkcja Bluetooth.", pt_PT="Bluetooth será ativado.", ro_RO="Se activează Bluetooth.", ru_RU="Bluetooth активируется.", sk_SK="Bluetooth sa aktivuje.", sl_SI="Bluetooth bo aktiviran.", sr_RS="Bluetooth se aktivira.", sv_SE="Bluetooth aktiveras.", tr_TR="Bluetooth etkinleştiriliyor.", uk_UA="Bluetooth активується.")
phone_not_attached__carplay_but_no_hfp_pid__text = TextObject(bs_BA="%1 je povezan s Apple CarPlay i može se koristiti samo na MMI.\nŽelite li povezati još jedan pametni telefon?", cs_CZ="%1 je připojeno k Apple CarPlay a lze jej použít pouze na MMI.\nChcete připojit další smartphone?", da_DK="%1 er forbundet med Apple CarPlay og kan kun anvendes i MMI.\nVil du forbinde endnu en smartphone?", de_DE="%1 ist mit Apple CarPlay verbunden und kann nur auf dem MMI\ngenutzt werden. Möchtest du ein weiteres Smartphone verbinden?", el_GR="Το %1 είναι συνδεδεμένο με το Apple CarPlay και μπορεί να\nχρησιμοποιηθεί μόνο στο MMI. Θέλετε να συνδέσετε ένα ακόμη smartphone;", en_GB="%1 is connected via Apple CarPlay and can only be operated\nusing the MMI. Do you want to connect an additional smartphone?", es_ES="%1 está conectado con Apple CarPlay y solo se puede utilizar en\nel MMI. ¿Desea conectar otro smartphone?", fi_FI="%1 on yhdistetty Apple CarPlayhin ja sitä voi käyttää vain MMI:n\nkautta. Haluatko yhdistää toisen älypuhelimen?", fr_FR="%1 est connecté à Apple CarPlay et peut être utilisé\nuniquement via le MMI. Souhaitez-vous connecter un smartphone supplémentaire?", hr_HR="%1 je spojen s Apple CarPlayjem i može se koristiti samo u MMI­ju.\nŽelite li spojiti još jedan smartphone?", hu_HU="%1 csatlakozik az Apple CarPlay-hez, és csak az MMI-n\nhasználható. Szeretnél csatlakoztatni egy másik okostelefont?", it_IT="%1 è collegato ad Apple CarPlay e può essere utilizzato solo\nsull'MMI. Collegare un altro smartphone?", nl_NL="%1 is verbonden met Apple CarPlay en kan alleen op de MMI\nworden gebruikt. Wil je een andere smartphone aansluiten?", no_NO="%1 har forbindelse med Apple CarPlay og kan bare brukes på\nMMI. Vil du opprette forbindelse med en smarttelefon til?", pl_PL="%1 jest połączony z Apple CarPlay i może być używany tylko w\nMMI. Czy chcesz podłączyć inny smartfon?", pt_PT="%1 está ligado a Apple CarPlay e só pode ser usado no MMI.\nQueres ligar outro smartphone?", ro_RO="%1 este conectat cu Apple CarPlay şi poate fi utilizat numai pe\nMMI. Doriţi să conectaţi încă un smartphone?", ru_RU="%1 подключен к Apple CarPlay и может использоваться только\nна MMI. Хотите подключить другой смартфон?", sk_SK="%1 je pripojený k Apple CarPlay a je možné ho použiť iba v\nsystéme MMI. Chcete pripojiť ďalší smartfón?", sl_SI="Naprava %1 je povezana z Apple CarPlay in jo je mogoče\nuporabljati samo v sistemu MMI. Ali želite povezati dodaten pametni telefon?", sr_RS="%1 je povezan sa Apple CarPlay i može da se koristi samo na\nMMI. Da li želite da povežete još jedan pametni telefon?", sv_SE="%1 är ansluten till Apple CarPlay och kan endast användas på\nMMI. Vill du ansluta en smartphone till?", tr_TR="%1 Apple CarPlay ile bağlı ve yalnızca MMI'da kullanılabilir.\nBaşka bir akıllı telefon bağlamak istiyor musun?", uk_UA="%1 підключено до Apple CarPlay і його можна\nвикористовувати лише на MMI. Хочете підключити інший смартфон?")
phone_not_attached__connect_phone__button_text = TextObject(bs_BA="Povežite mobilni telefon", cs_CZ="Připojte prosím mobilní telefon", da_DK="Forbind mobiltelefon.", de_DE="Bitte Mobiltelefon verbinden", el_GR="Συνδέστε ένα κινητό τηλέφωνο", en_GB="Please connect mobile phone", es_ES="Por favor, conecte el teléfono móvil", fi_FI="Yhdistä matkapuhelin", fr_FR="Veuillez connecter un téléphone portable", hr_HR="Spojiti mobilni telefon", hu_HU="Csatlakoztassa a mobiltelefont", it_IT="Collegare il telefono cellulare", nl_NL="Maak verbinding met uw mobiele telefoon", no_NO="Opprett forbindelse med en mobiltelefon", pl_PL="Proszę podłączyć telefon komórkowy", pt_PT="Por favor, ligue um telemóvel", ro_RO="Conectaţi telefonul mobil", ru_RU="Подключите мобильный телефон", sk_SK="Prosím, pripojte mobilný telefón", sl_SI="Povežite mobilni telefon", sr_RS="Povežite mobilni telefon", sv_SE="Anslut mobiltelefonen", tr_TR="Lütfen mobil telefonu bağlayın", uk_UA="Підключіть мобільний телефон")
phone_not_attached__connecting_new_phone_not_allowed_while_driving = TextObject(bs_BA="Povežite pametni telefon. Tokom vožnje je moguće samo\npovezivanje poznatih uređaja.", cs_CZ="Připojte smartphone. Během jízdy lze připojit pouze známá zařízení.", da_DK="Opret forbindelse til en smartphone.\nUnder kørsel er det kun kendte apparater, der kan oprettes forbindelse til.", de_DE="Bitte verbinde ein Smartphone. Während der Fahrt können nur bekannte Geräte verbunden\nwerden.", el_GR="Συνδέστε ένα smartphone. Κατά τη διαδρομή μπορούν να συνδεθούν μόνο γνωστές συσκευές.", en_GB="Please connect a smartphone. Only known devices can be connected while driving.", es_ES="Por favor, conecte un smartphone. Durante la marcha solo se pueden conectar\ndispositivos conocidos.", fi_FI="Yhdistä älypuhelin. Ajon aikana voidaan yhdistää vain tunnettuja laitteita.", fr_FR="Veuillez connecter un smartphone.\nSeuls les périphériques connus peuvent être connectés pendant la conduite.", hr_HR="Spojite smartphone. Tijekom vožnje moguće je spojiti samo poznate uređaje.", hu_HU="Csatlakoztass egy okostelefont. Vezetés közben csak ismert eszközök csatlakoztathatók.", it_IT="Collegare uno smartphone. Durante la marcia è possibile collegare solo i dispositivi conosciuti.", nl_NL="Verbind een smartphone. Tijdens de rit kunnen alleen bekende apparaten worden verbonden.", no_NO="Opprett forbindelse med en smarttelefon. Det kan bare opprettes forbindelse med kjente\nenheter under kjøring.", pl_PL="Podłącz smartfon. Podczas jazdy można podłączać tylko znane urządzenia.", pt_PT="Por favor, liga um smartphone. Durante a viagem só podem ser ligados aparelhos conhecidos.", ro_RO="Conectaţi un smartphone. În timpul deplasării pot fi conectate numai dispozitive cunoscute.", ru_RU="Подключите смартфон. Во время поездки можно подключать только известные устройства.", sk_SK="Prosím, pripojte smartfón. Počas jazdy je možné pripojiť len známe zariadenia.", sl_SI="Povežite pametni telefon. Med vožnjo je mogoče povezati samo znane naprave.", sr_RS="Molimo da povežete pametni telefon. Tokom vožnje moguće je samo\npovezivanje poznatih uređaja.", sv_SE="Anslut en smartphone. Under körningen kan endast bekanta enheter anslutas.", tr_TR="Lütfen bir akıllı telefon bağla. Sürüş sırasında sadece bilinen cihazlar bağlanabilir.", uk_UA="Підключіть смартфон. Під час поїздки можна підключати тільки відомі пристрої.")
